import subprocess, shlex, sys, os

os.environ['TOOL_LOG'] = 'off'
SKILL_DIR = os.path.dirname(os.path.abspath(__file__))


def _run(cmd):
    result = subprocess.run(cmd, shell=True, text=True, capture_output=True, env=os.environ)
    if result.returncode != 0 and result.stderr.strip():
        return f'CLI ERROR (exit {result.returncode}): {result.stderr.strip()}'
    return result.stdout


def do_list():
    # implement listing logic
    return 'STATUS: Success. <results>'


def do_read(item_id):
    # implement read logic
    return f'STATUS: Success. CONTENT OF {item_id}:\n\n<body>'


def do_send(to, subject, body):
    # implement send/create logic
    return f'STATUS: Success. Sent to {to}.'


cmd = sys.argv[1] if len(sys.argv) > 1 else 'list'

if cmd == 'list':
    print(do_list())

elif cmd == 'read':
    if len(sys.argv) < 3:
        print('STATUS: Failed. Usage: wrapper.py read <id>')
        sys.exit(1)
    print(do_read(sys.argv[2]))

elif cmd == 'send':
    if len(sys.argv) < 5:
        print('STATUS: Failed. Usage: wrapper.py send <to> <subject> <body>')
        sys.exit(1)
    print(do_send(sys.argv[2], sys.argv[3], sys.argv[4]))

else:
    print(f'STATUS: Failed. Unknown command: {cmd}. Use: list | read <id> | send <to> <subject> <body>')
    sys.exit(1)
